from datetime import datetime
import json

# Get current schema metadata from Get Schema Metadata node
current_schema = _input.all()[0].get('json', {})

# Get historical baselines from Get Historical Baselines node
historical_data = _input.all()[1].get('json', {})

issues = []

# Parse current schema and historical baselines
if isinstance(current_schema, list):
    current_tables = {item.get('table_name'): item for item in current_schema}
else:
    current_tables = {current_schema.get('table_name'): current_schema}

if isinstance(historical_data, list):
    historical_tables = {item.get('table_name'): item for item in historical_data}
else:
    historical_tables = {historical_data.get('table_name'): historical_data}

timestamp = datetime.utcnow().isoformat()

# Check for schema drift
for table_name, current_table in current_tables.items():
    if table_name not in historical_tables:
        # New table detected
        issues.append({
            'type': 'schema_drift',
            'severity': 'medium',
            'table_name': table_name,
            'column_name': None,
            'change_description': f'New table {table_name} detected',
            'detected_at': timestamp
        })
        continue

    historical_table = historical_tables[table_name]
    current_columns = current_table.get('columns', {})
    historical_columns = historical_table.get('columns', {})

    # Check for added columns
    for col_name, col_info in current_columns.items():
        if col_name not in historical_columns:
            issues.append({
                'type': 'schema_drift',
                'severity': 'low',
                'table_name': table_name,
                'column_name': col_name,
                'change_description': f'New column {col_name} added to {table_name}',
                'detected_at': timestamp
            })

    # Check for removed columns
    for col_name in historical_columns:
        if col_name not in current_columns:
            issues.append({
                'type': 'schema_drift',
                'severity': 'high',
                'table_name': table_name,
                'column_name': col_name,
                'change_description': f'Column {col_name} removed from {table_name}',
                'detected_at': timestamp
            })

    # Check for data type changes
    for col_name, col_info in current_columns.items():
        if col_name in historical_columns:
            current_type = col_info.get('data_type')
            historical_type = historical_columns[col_name].get('data_type')

            if current_type != historical_type:
                issues.append({
                    'type': 'schema_drift',
                    'severity': 'high',
                    'table_name': table_name,
                    'column_name': col_name,
                    'change_description': f'Data type changed from {historical_type} to {current_type} for {col_name} in {table_name}',
                    'detected_at': timestamp
                })

            # Check for nullability changes
            current_nullable = col_info.get('is_nullable', True)
            historical_nullable = historical_columns[col_name].get('is_nullable', True)

            if current_nullable != historical_nullable:
                nullable_change = 'nullable' if current_nullable else 'not nullable'
                issues.append({
                    'type': 'schema_drift',
                    'severity': 'medium',
                    'table_name': table_name,
                    'column_name': col_name,
                    'change_description': f'Nullability changed to {nullable_change} for {col_name} in {table_name}',
                    'detected_at': timestamp
                })

# Check for removed tables
for table_name in historical_tables:
    if table_name not in current_tables:
        issues.append({
            'type': 'schema_drift',
            'severity': 'critical',
            'table_name': table_name,
            'column_name': None,
            'change_description': f'Table {table_name} has been removed',
            'detected_at': timestamp
        })

return issues

